+    const order = this.getCursorOrder(opts.orderBy);
+    if (!order.some(([field]) => field === this.crudConfig.id_field)) {
+      order.push([this.crudConfig.id_field, 'asc']);
+      const orderBy = Array.isArray(opts.orderBy)
+        ? [...opts.orderBy]
+        : [opts.orderBy];
+      orderBy.push({ [this.crudConfig.id_field]: 'asc' } as any);
+      opts.orderBy = orderBy as any;
